# ── σ-block-diagonal mask helpers (module-level frozen constants) ──────────
# Masks are module globals, NOT nn.Module attributes, so MLX never treats
# them as trainable parameters (the mlx analogue of a torch register_buffer).

def _block_diagonal_mask(in_mask: list, out_mask: list) -> mx.array:
    """(len(out_mask), len(in_mask)) binary mask: [i,j] = 1 iff
    out_mask[i] == in_mask[j]. Weights with mask==0 are forced to zero."""
    return mx.array(
        [[1.0 if out_mask[i] == in_mask[j] else 0.0
          for j in range(len(in_mask))]
         for i in range(len(out_mask))]
    )

def _decoder_head_offsets() -> list:
    offs, cur = [], 0
    for d in DECODER_LEVEL_DIMS:
        offs.append((cur, cur + d))
        cur += d
    return offs

_PHI_MASK     = _block_diagonal_mask(GMM_TOKEN_SIGMA_MASK, SIGMA64_MASK)
_SIGMA_MASK   = _block_diagonal_mask(SIGMA64_MASK, SIGMA64_MASK)
_HEAD_OFFSETS = _decoder_head_offsets()
_HEAD_MASKS   = [_block_diagonal_mask(SIGMA64_MASK, SIGMA768_MASK[lo:hi])
                 for (lo, hi) in _HEAD_OFFSETS]

# ── L3 encoder: σ-masked per-token linear (10 → 64), then sum-pool ───────

class L3Encoder(nn.Module):
    """Permutation-invariant set encoder: a SINGLE σ-block-diagonal linear
    (no bias), then sum-pool over tokens. Matches 'placeToken' in LookNetE.hs."""

    def __init__(self):
        super().__init__()
        self.phi = nn.Linear(GMM_TOKEN_DIM, MODEL_DIM, bias=False)

    def __call__(self, tokens, token_mask=None):
        w = self.phi.weight * _PHI_MASK            # σ-mask applied at call time
        h = tokens @ w.T                           # (B, MAX_TOKENS, 64)
        if token_mask is not None:
            h = h * mx.expand_dims(token_mask, -1)
        return mx.sum(h, axis=1)                   # (B, 64) — sum-pool (perm-invariant)

# ── L4 core: ONE shared block reused over 8 Haar levels (Mixture-of-Recursions) ──

class SharedBlock(nn.Module):
    """The ONE weight-shared block reused across all CORE_DEPTH recursion
    steps. `refine` is the σ-equivariant residual update x ↦ x + φ(x) (φ a
    two-layer σ-block-diagonal MLP, tanh between). `halt` is the σ-INVARIANT
    halting head λ_ℓ ∈ [0,1] — it reads ONLY (‖achroma‖², ‖chroma‖²), so a
    chroma sign flip cannot change λ_ℓ (mirrors LookNetR.sigmaInvariantFeatures)."""

    def __init__(self):
        super().__init__()
        self.w1 = nn.Linear(MODEL_DIM, MODEL_DIM, bias=False)
        self.w2 = nn.Linear(MODEL_DIM, MODEL_DIM, bias=False)
        self.halt_mlp = nn.Linear(HALT_FEATURE_DIM, 1)

    def refine(self, x):
        w1 = self.w1.weight * _SIGMA_MASK
        w2 = self.w2.weight * _SIGMA_MASK
        # tanh is ODD — required for σ-equivariance under sign-flip involutions.
        dx = mx.tanh(x @ w1.T)
        dx = dx @ w2.T
        return x + dx

    def halt(self, x):
        # σ-invariant features: squares kill the chromatic sign flip exactly.
        achroma = x[..., :HIDDEN_ACHROMATIC_DIM]
        chroma  = x[..., HIDDEN_ACHROMATIC_DIM:]
        feats = mx.stack([
            mx.sum(achroma * achroma, axis=-1),
            mx.sum(chroma * chroma, axis=-1),
        ], axis=-1)                                # (B, HALT_FEATURE_DIM)
        return mx.sigmoid(self.halt_mlp(feats))    # (B, 1) — λ_ℓ ∈ [0,1]

    def __call__(self, x):
        return self.refine(x)

class L4Recursion(nn.Module):
    """ONE SharedBlock reused RECURSION_STEPS (= CORE_DEPTH = 8) times. Returns
    the per-step context sequence [ctx0, …, ctx_CORE_DEPTH] (length CORE_DEPTH+1)
    so the decoder's level-ℓ head reads the context after ℓ refinements. Static
    unroll; halting λ_ℓ is exposed for the trainer's soft-PonderNet objective
    but does NOT gate control flow."""

    def __init__(self):
        super().__init__()
        self.g = SharedBlock()                     # exactly ONE shared block

    def __call__(self, x):
        contexts = [x]
        for _ in range(RECURSION_STEPS):
            x = self.g(x)                          # reuse the shared block
            contexts.append(x)
        return contexts                            # length CORE_DEPTH + 1

# ── L5 decoder: per-level Haar heads reading per-step contexts ─────────────

class L5Decoder(nn.Module):
    """Nine σ-block-diagonal heads (root + 8 Haar levels); head i reads
    contexts[i] (deeper recursion → finer detail). Sum of head sizes =
    sum(DECODER_LEVEL_DIMS) = 768. Mirrors LookNetD.decoderFromRecursion."""

    def __init__(self):
        super().__init__()
        self.heads = [nn.Linear(MODEL_DIM, d, bias=False) for d in DECODER_LEVEL_DIMS]

    def __call__(self, contexts):
        outs = []
        for i, head in enumerate(self.heads):
            w = head.weight * _HEAD_MASKS[i]
            outs.append(contexts[i] @ w.T)         # head i ← context i
        return mx.concatenate(outs, axis=-1)       # (B, 768)

# ── The full pipeline ──────────────────────────────────────────────────────

class LookNet(nn.Module):
    """E :> R :> D, σ-equivariant end-to-end by
    SixFour.Spec.LookNetCompose.lookNetSigmaTheorem."""

    def __init__(self):
        super().__init__()
        self.encoder   = L3Encoder()
        self.recursion = L4Recursion()
        self.decoder   = L5Decoder()

    def __call__(self, tokens, token_mask=None):
        h = self.encoder(tokens, token_mask=token_mask)   # (B, 64)
        contexts = self.recursion(h)                      # [ (B,64) ] × (CORE_DEPTH+1)
        return self.decoder(contexts)                     # (B, 768)
